import scala.collection.mutable

def solve(weight: Array[Long]): Long = {
  val n = weight.length
  if (n < 2) return 0L

  val stack = mutable.Stack[Int]()
  val pge = Array.fill(n)(-1)
  for (i <- 0 until n) {
    while (stack.nonEmpty && weight(stack.top) <= weight(i)) {
      stack.pop()
    }
    if (stack.nonEmpty) {
      pge(i) = stack.top
    } else {
      pge(i) = -1
    }
    stack.push(i)
  }

  val subarrays = mutable.ListBuffer[(Int, Int)]()
  for (i <- 0 until n) {
    if (pge(i) != -1) {
      subarrays.append((pge(i), i))
    }
  }

  subarrays.sortWith((a, b) => a._2 < b._2)

  var count = 0L
  var lastEnd = -1
  for ((start, end) <- subarrays) {
    if (start > lastEnd) {
      count += 1
      lastEnd = end
    }
  }

  count
}
